USE Subsidy_system;
GO

/*
数据库完整数据恢复脚本

用途：
1. 清除“建表.sql”自带的少量初始数据或此前导入的数据；
2. 导入本项目最终使用的完整数据；
3. 确保重复执行仍能得到相同的数据量。

重要注意事项：
- 本脚本会删除 Subsidy_system 中八张业务表的现有数据，请勿在需要保留原数据的数据库中执行。
- 必须先执行“建表.sql”和“触发器代码.sql”。
- 导入期间会临时停用触发器，防止历史数据被重新计算或额外生成预警；导入成功后自动重新启用。
- 全部操作放在事务中，任意一条语句失败时会自动回滚。
*/

SET NOCOUNT ON;
SET XACT_ABORT ON;

BEGIN TRY
    BEGIN TRANSACTION;

    -- 导入历史快照时停用触发器，确保金额、状态和预警与导出文件完全一致。
    DISABLE TRIGGER ALL ON dbo.DiningRecord;
    DISABLE TRIGGER ALL ON dbo.Elderly;
    DISABLE TRIGGER ALL ON dbo.SubsidyQualification;
    DISABLE TRIGGER ALL ON dbo.SubsidyRule;
    DISABLE TRIGGER ALL ON dbo.SettlementSheet;

    -- 按外键依赖从子表到父表清空数据。不能随意改变删除顺序。
    DELETE FROM dbo.AbnormalWarning;
    DELETE FROM dbo.DiningRecord;
    DELETE FROM dbo.SettlementSheet;
    DELETE FROM dbo.SubsidyQualification;
    DELETE FROM dbo.SubsidyRule;
    DELETE FROM dbo.Elderly;
    DELETE FROM dbo.DiningPoint;
    DELETE FROM dbo.AuditLog;

    DBCC CHECKIDENT ('dbo.AuditLog', RESEED, 0);

-- Elderly (50条)

-- DiningPoint (5条)

-- SubsidyRule (4条)

-- SubsidyQualification (50条)

-- DiningRecord (2363条)

-- SettlementSheet (45条)

-- AbnormalWarning (24条)

    -- 恢复正常业务触发器。
    ENABLE TRIGGER ALL ON dbo.DiningRecord;
    ENABLE TRIGGER ALL ON dbo.Elderly;
    ENABLE TRIGGER ALL ON dbo.SubsidyQualification;
    ENABLE TRIGGER ALL ON dbo.SubsidyRule;
    ENABLE TRIGGER ALL ON dbo.SettlementSheet;

    COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;
    THROW;
END CATCH;
GO

-- 导入后的核验结果。正确结果应为：50、5、4、50、2363、45、24。
SELECT N'Elderly' AS TableName, COUNT(*) AS RowCount FROM dbo.Elderly
UNION ALL SELECT N'DiningPoint', COUNT(*) FROM dbo.DiningPoint
UNION ALL SELECT N'SubsidyRule', COUNT(*) FROM dbo.SubsidyRule
UNION ALL SELECT N'SubsidyQualification', COUNT(*) FROM dbo.SubsidyQualification
UNION ALL SELECT N'DiningRecord', COUNT(*) FROM dbo.DiningRecord
UNION ALL SELECT N'SettlementSheet', COUNT(*) FROM dbo.SettlementSheet
UNION ALL SELECT N'AbnormalWarning', COUNT(*) FROM dbo.AbnormalWarning;

SELECT
    SUM(CASE WHEN AccountStatus = N'正常' THEN 1 ELSE 0 END) AS NormalElderly,
    (SELECT COUNT(*) FROM dbo.DiningRecord) AS DiningRecordCount,
    (SELECT CAST(SUM(SubsidyAmount) AS DECIMAL(18,2)) FROM dbo.DiningRecord) AS TotalSubsidyAmount,
    (SELECT COUNT(*) FROM dbo.AbnormalWarning WHERE HandleStatus IN (N'待处理', N'处理中')) AS PendingWarningCount,
    (SELECT COUNT(*) FROM dbo.DiningPoint WHERE OperationStatus = N'正常运营') AS ActiveDiningPointCount
FROM dbo.Elderly;
GO
